import Component from 'flarum/common/Component';
import FieldEdit from './FieldEdit';
export default class FieldList extends Component {
  view() {
    const {
      existing,
      new: newField,
      loading,
      onUpdate
    } = this.attrs;
    return m("form", {
      className: "form js-sortable-fields"
    }, existing.map(field => m(FieldEdit, {
      field: field,
      loading: loading,
      onUpdate: onUpdate
    })), m(FieldEdit, {
      field: newField,
      loading: loading,
      onUpdate: onUpdate
    }));
  }
}
flarum.reg.add('fof-masquerade', 'admin/components/FieldList', FieldList);